+  // First EMA is SMA
+  let ema = data.slice(0, period).reduce((a, b) => a + b, 0) / period;
+
+  for (let i = 0; i < data.length; i++) {
+    if (i < period - 1) {
+      result.push(null);
+    } else if (i === period - 1) {
+      result.push(ema);
+    } else {
+      ema = (data[i] - ema) * multiplier + ema;
+      result.push(ema);
