+      market: '◉',
+      sector: '●',
+      industry: '○',
+      stock: '·'
+    };
+
+    for (const [entity, emb] of embedding.embeddings) {
+      const x = emb[0];
+      const y = emb[1];
+
+      const gridX = Math.floor((x + 1) / 2 * (width - 1));
+      const gridY = Math.floor((1 - y) / 2 * (height - 1));
+
+      if (gridY >= 0 && gridY < height && gridX >= 0 && gridX < width) {
