+      signal = 1;   // Long - price too low
+      confidence = Math.min(0.9, (Math.abs(zscore) - this.zscoreThreshold) * 0.3);
+    }
+
+    const result = {
+      signal,
+      confidence: confidence * this.confidence,
+      reason: `zscore=${zscore.toFixed(2)}, mean=${mean.toFixed(2)}, std=${std.toFixed(4)}`,
