+      if ((actual > 0) === (predicted > 0)) correctDir++;
+      total++;
+    }
+  }
+
+  return {
+    mae: maeSum / total,
+    rmse: Math.sqrt(mseSum / total),
+    r2: 1 - ssRes / ssTot,
+    directionAccuracy: correctDir / total
+  };
