+    const predicted = predictions[i][horizon - 1];
+
+    maeSum += Math.abs(actual - predicted);
+    if ((actual > 0) === (predicted > 0)) correctDir++;
+    if (Math.abs(actual - predicted) < 0.005) hits++;
+  }
+
+  return {
+    mae: maeSum / y.length,
+    direction: correctDir / y.length,
+    hitRate: hits / y.length
+  };
+}
