+  finalValues.sort((a, b) => a - b);
+
+  const percentiles = {};
+  for (const p of [1, 5, 10, 25, 50, 75, 90, 95, 99]) {
+    percentiles[p] = Math.round(finalValues[Math.floor(p / 100 * config.simulations)]);
+  }
